import { afterEach, describe, expect, it, vi } from "vitest";
import { runLogin } from "./login.js";
const SIGN_IN_URL = "https://test.invalid/studio/sign-in?redirect_url=%2Fstudio%2Fclose";
const mockAbort = vi.fn();
let mockReuseWindow = false;
const mockOpenStudioTo = vi.fn(async (_path, opts) => {
    if (!mockReuseWindow) {
        opts.onWindowOpened?.(SIGN_IN_URL);
    }
    opts.onLoginRequired?.("test-session", SIGN_IN_URL);
    return {
        abort: mockAbort,
        done: Promise.resolve(),
        sessionId: "test-session",
    };
});
vi.mock("./openStudioTo.js", () => ({
    formatStudioUrlMessage: (url) => `Studio opened at: ${url}`,
    openStudioTo: (...args) => mockOpenStudioTo(...args),
    StudioNavigationError: class StudioNavigationError extends Error {
    },
}));
let mockAuthenticated = false;
vi.mock("../config.js", () => ({
    getConfig: () => ({
        serviceUrl: "https://test.invalid",
        apiKey: mockAuthenticated ? "test-key" : null,
    }),
    hasCredentials: () => mockAuthenticated,
}));
vi.mock("../analytics.js", () => ({
    reportHandoff: vi.fn().mockResolvedValue(undefined),
}));
const platform = {};
afterEach(() => {
    vi.restoreAllMocks();
    mockOpenStudioTo.mockClear();
    mockAbort.mockClear();
    mockAuthenticated = false;
    mockReuseWindow = false;
});
function mockWhoAmI(ok) {
    return vi.spyOn(globalThis, "fetch").mockResolvedValue(ok
        ? new Response(JSON.stringify({
            user: { id: "u1", email: "ruven@goharvest.ai", fullName: null },
            organization: { id: "org1" },
        }), { status: 200 })
        : new Response(JSON.stringify({ error: "unauthorized" }), {
            status: 401,
        }));
}
describe("runLogin", () => {
    it("prints the sign-in URL on the Studio opened line", async () => {
        vi.spyOn(globalThis, "fetch").mockResolvedValue(new Response(JSON.stringify({
            user: { id: "u1", email: "ruven@goharvest.ai", fullName: null },
            organization: { id: "org1" },
        }), { status: 200 }));
        const log = vi.spyOn(console, "log").mockImplementation(() => { });
        await runLogin(platform, "0.0.0-test", { exitOnComplete: false });
        const openingLine = log.mock.calls
            .map((call) => String(call[0]))
            .find((line) => line.includes("Studio opened at"));
        expect(openingLine).toContain(SIGN_IN_URL);
        expect(log.mock.calls
            .map((call) => String(call[0]))
            .filter((line) => line.includes("Studio opened at"))).toHaveLength(1);
    });
    it("prints the sign-in URL when Studio reuses a keyless login window", async () => {
        mockReuseWindow = true;
        vi.spyOn(globalThis, "fetch").mockResolvedValue(new Response(JSON.stringify({
            user: { id: "u1", email: "ruven@goharvest.ai", fullName: null },
            organization: { id: "org1" },
        }), { status: 200 }));
        const log = vi.spyOn(console, "log").mockImplementation(() => { });
        await runLogin(platform, "0.0.0-test", { exitOnComplete: false });
        const openingLine = log.mock.calls
            .map((call) => String(call[0]))
            .find((line) => line.includes("Studio opened at"));
        expect(openingLine).toContain(SIGN_IN_URL);
    });
    it("targets Studio home for reuse and the self-closing page for a fresh window, in one call", async () => {
        vi.spyOn(globalThis, "fetch").mockResolvedValue(new Response(JSON.stringify({
            user: { id: "u1", email: "ruven@goharvest.ai", fullName: null },
            organization: { id: "org1" },
        }), { status: 200 }));
        vi.spyOn(console, "log").mockImplementation(() => { });
        await runLogin(platform, "0.0.0-test", { exitOnComplete: false });
        const path = String(mockOpenStudioTo.mock.calls[0]?.[0]);
        const opts = mockOpenStudioTo.mock.calls[0]?.[1];
        expect(path).toBe("/studio");
        expect(opts.freshWindowPath).toContain("autoClose=true");
        expect(path).not.toContain("pluginLogin");
        expect(opts.freshWindowPath).not.toContain("pluginLogin");
    });
    it("aborts the channel after login completes", async () => {
        mockWhoAmI(true);
        vi.spyOn(console, "log").mockImplementation(() => { });
        await runLogin(platform, "0.0.0-test", { exitOnComplete: false });
        expect(mockAbort).toHaveBeenCalledOnce();
    });
    it("short-circuits when already authenticated with a verified key", async () => {
        mockAuthenticated = true;
        mockWhoAmI(true);
        const log = vi.spyOn(console, "log").mockImplementation(() => { });
        await runLogin(platform, "0.0.0-test", { exitOnComplete: false });
        expect(mockOpenStudioTo).not.toHaveBeenCalled();
        const printed = log.mock.calls.map((c) => String(c[0])).join("\n");
        expect(printed).toContain("Already logged in as ruven@goharvest.ai");
        expect(printed).toContain("--force");
    });
    it("--force bypasses the short-circuit and ignores the stored key", async () => {
        mockAuthenticated = true;
        mockWhoAmI(true);
        vi.spyOn(console, "log").mockImplementation(() => { });
        await runLogin(platform, "0.0.0-test", {
            exitOnComplete: false,
            force: true,
        });
        expect(mockOpenStudioTo).toHaveBeenCalledOnce();
        const opts = mockOpenStudioTo.mock.calls[0]?.[1];
        expect(opts.forceLogin).toBe(true);
    });
    it("falls through to a real login when the stored key fails verification", async () => {
        mockAuthenticated = true;
        mockWhoAmI(false);
        vi.spyOn(console, "log").mockImplementation(() => { });
        await runLogin(platform, "0.0.0-test", { exitOnComplete: false });
        expect(mockOpenStudioTo).toHaveBeenCalledOnce();
        const opts = mockOpenStudioTo.mock.calls[0]?.[1];
        expect(opts.forceLogin).toBe(true);
    });
});
